source:
Token -> {
  -> Number:
  -> Word:
  -> Punct:
}

Number -> { i64:value }
Word -> { String:text }
Punct -> { String:symbol }

digit -> '0'..'9'
letter -> 'a'..'z' | 'A'..'Z'

lex -> {
  String:source
  -> source.head ? {
    digit -> Number{value -> 0}
    letter -> Word{text -> source}
    -> Punct{symbol -> source}
  }
}

parse -> {
  Token:tok
  -> tok ? {
    Number:(n) -> n.value
    Word:(w) -> w.text
    Punct:(p) -> p.symbol
  }
}
